+++ b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
@@ -1923,6 +1923,9 @@ void VPlanTransforms::dropPoisonGeneratingRecipes(
         Instruction *Instr = dyn_cast_or_null<Instruction>(
             CurRec->getVPSingleValue()->getUnderlyingValue());
         (void)Instr;
+        // Drop poison-generating flags on CallInst as they are not captured by VPRecipeWithIRFlags.
+        if (Instr && isa<CallInst>(Instr) && Instr->hasPoisonGeneratingFlags())
+          Instr->dropPoisonGeneratingFlags();
         assert((!Instr || !Instr->hasPoisonGeneratingFlags()) &&
                "found instruction with poison generating flags not covered by "
                "VPRecipeWithIRFlags");
